('dc6e2188-eff3-57fb-b1ff-b2b7c9b68599', 3, 'enriched_coasting_tell', 'positive', NULL, 'Solo RPLS Ray Lynn Vannoy for 48+ years (RPLS #1988 granted 1978) — sole identified RPLS at firm per TBPELS + live team page.', 'enrichment', 'https://www.vannoyassoc.com/', '2026-05-16'),
('dc6e2188-eff3-57fb-b1ff-b2b7c9b68599', 3, 'enriched_coasting_tell', 'positive', NULL, 'Direct personal contact (cell + personal email) is the only contact method — classic solo-owner-operator posture.', 'enrichment', 'https://www.vannoyassoc.com/', '2026-05-16'),
